<?php if (!defined('ABSPATH')) exit; ?>
<div class="wrap sc-admin"><h1>Mockups</h1><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><input type="hidden" name="action" value="shakass_save_mockups"><?php wp_nonce_field('shakass_save_mockups'); ?><?php foreach($mockups as $i=>$m): ?><section class="sc-card"><h2><?php echo esc_html($m['name']); ?></h2><label>Produit<select name="mockups[<?php echo $i; ?>][product]"><?php foreach($products as $p) echo '<option value="'.esc_attr($p['slug']).'" '.selected($m['product'],$p['slug'],false).'>'.esc_html($p['name']).'</option>'; ?></select></label><label>Nom<input name="mockups[<?php echo $i; ?>][name]" value="<?php echo esc_attr($m['name']); ?>"></label><label>Image recto URL<input name="mockups[<?php echo $i; ?>][front_image]" value="<?php echo esc_attr($m['front_image']); ?>"></label><label>Image verso URL<input name="mockups[<?php echo $i; ?>][back_image]" value="<?php echo esc_attr($m['back_image']); ?>"></label><label>Couleur<input type="color" name="mockups[<?php echo $i; ?>][color]" value="<?php echo esc_attr($m['color']); ?>"></label><label><input type="checkbox" name="mockups[<?php echo $i; ?>][active]" value="1" <?php checked(!empty($m['active'])); ?>> Actif</label><div class="sc-admin-grid"><fieldset><legend>Zone recto (%)</legend><?php foreach(['x','y','w','h'] as $k): ?><label><?php echo esc_html($k); ?><input type="number" step="0.1" name="mockups[<?php echo $i; ?>][front_<?php echo $k; ?>]" value="<?php echo esc_attr((string)$m['front_zone'][$k]); ?>"></label><?php endforeach; ?></fieldset><fieldset><legend>Zone verso (%)</legend><?php foreach(['x','y','w','h'] as $k): ?><label><?php echo esc_html($k); ?><input type="number" step="0.1" name="mockups[<?php echo $i; ?>][back_<?php echo $k; ?>]" value="<?php echo esc_attr((string)$m['back_zone'][$k]); ?>"></label><?php endforeach; ?></fieldset></div></section><?php endforeach; ?><button class="button button-primary">Enregistrer les mockups</button></form></div>
